package systemcontract

import (
	"math"
	"math/big"

	"github.com/ethereum/go-ethereum/common"
	"github.com/ethereum/go-ethereum/consensus/congress/vmcaller"
	"github.com/ethereum/go-ethereum/core"
	"github.com/ethereum/go-ethereum/core/state"
	"github.com/ethereum/go-ethereum/core/types"
	"github.com/ethereum/go-ethereum/log"
	"github.com/ethereum/go-ethereum/params"
)

// rewardPoolCode is the deployed runtime bytecode of the RewardPool contract.
// Compiled with solc 0.6.12 --optimize --optimize-runs 200.
// Admin calls burn(amount) to send fees to 0xdEaD, or withdraw(to, amount) to pull funds out.
const rewardPoolCode = ""

type hardForkRewardPool struct{}

func (s *hardForkRewardPool) GetName() string {
	return RewardPoolContractName
}

func (s *hardForkRewardPool) Update(config *params.ChainConfig, height *big.Int, state *state.StateDB) error {
	contractCode := common.FromHex(rewardPoolCode)
	state.SetCode(RewardPoolContractAddr, contractCode)
	log.Info("Deployed RewardPool system contract", "addr", RewardPoolContractAddr, "block", height)
	return nil
}

func (s *hardForkRewardPool) getAdminByChainId(chainId *big.Int) common.Address {
	if chainId.Cmp(params.G8MainnetChainID) == 0 {
		return devAdmin
	}
	return devAdminTestnet
}

func (s *hardForkRewardPool) Execute(state *state.StateDB, header *types.Header, chainContext core.ChainContext, config *params.ChainConfig) error {
	method := "initialize"
	data, err := GetInteractiveABI()[RewardPoolContractName].Pack(method, s.getAdminByChainId(config.ChainID))
	if err != nil {
		log.Error("Can't pack data for RewardPool initialize", "error", err)
		return err
	}
	msg := vmcaller.NewLegacyMessage(header.Coinbase, &RewardPoolContractAddr, 0, new(big.Int), math.MaxUint64, new(big.Int), data, false)
	_, err = vmcaller.ExecuteMsg(msg, state, header, chainContext, config)
	return err
}
